import ast

def find_syntax_error(code):
    try:
        tree = ast.parse(code)
        return None, tree
    except SyntaxError as e:
        return {
            "type": "SyntaxError",
            "line": e.lineno,
            "message": e.msg
        }, None


def find_logical_issues(code, tree):
    issues = []
    lines = code.split("\n")

    # ---- Division by zero ----
    for i, line in enumerate(lines, start=1):
        if "/0" in line.replace(" ", ""):
            issues.append(("Division by zero", i))

    # ---- try without except ----
    if "try:" in code and "except" not in code:
        issues.append(("Try block without except", 0))

    # ---- Input inside loop (TLE risk) ----
    for node in ast.walk(tree):
        if isinstance(node, (ast.For, ast.While)):
            for n in ast.walk(node):
                if isinstance(n, ast.Call) and hasattr(n.func, "id") and n.func.id == "input":
                    issues.append(("Input inside loop (slow I/O, TLE risk)", node.lineno))

    # ---- Infinite loop ----
    for node in ast.walk(tree):
        if isinstance(node, ast.While):
            if isinstance(node.test, ast.Constant) and node.test.value is True:
                issues.append(("Possible infinite loop", node.lineno))

    # ---- Nested loops (O(n^2)) ----
    for node in ast.walk(tree):
        if isinstance(node, ast.For):
            for child in ast.walk(node):
                if isinstance(child, ast.For) and child != node:
                    issues.append(("Nested loop (possible O(n^2), TLE risk)", child.lineno))

    # ---- Sorting inside loop ----
    for node in ast.walk(tree):
        if isinstance(node, ast.For):
            for n in ast.walk(node):
                if isinstance(n, ast.Call) and hasattr(n.func, "attr") and n.func.attr == "sort":
                    issues.append(("Sorting inside loop (TLE risk)", node.lineno))

    # ---- Missing return ----
    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef):
            has_return = any(isinstance(n, ast.Return) for n in ast.walk(node))
            if not has_return:
                issues.append(("Function has no return", node.lineno))

    # ---- Recursion without base case ----
    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef):
            calls_self = any(isinstance(n, ast.Call) and getattr(n.func, "id", None) == node.name for n in ast.walk(node))
            has_if = any(isinstance(n, ast.If) for n in ast.walk(node))
            if calls_self and not has_if:
                issues.append(("Recursion without base case", node.lineno))

    # ---- Modifying list while iterating ----
    for node in ast.walk(tree):
        if isinstance(node, ast.For):
            for n in ast.walk(node):
                if isinstance(n, ast.Call) and hasattr(n.func, "attr") and n.func.attr in ["append", "remove"]:
                    issues.append(("Modifying list while iterating", node.lineno))

    return issues

